CREATE POLICY "Admins update order items" ON public.order_items FOR UPDATE TO authenticated USING (has_role(auth.uid(), 'admin'::app_role)) WITH CHECK (has_role(auth.uid(), 'admin'::app_role));
CREATE POLICY "Admins delete order items" ON public.order_items FOR DELETE TO authenticated USING (has_role(auth.uid(), 'admin'::app_role));